mapper.select:
SELECT h.id, h.hazard_type AS hazardType, h.hazard_level AS hazardLevel, h.hazard_source AS hazardSource, h.user_id AS userId, u.user_name AS userName, h.area_code AS areaCode, CONCAT( IFNULL(l1.area_name, ''), IF(l1.area_name IS NOT NULL AND l2.area_name IS NOT NULL, '/', ''), IFNULL(l2.area_name, ''), IF(l2.area_name IS NOT NULL AND l3.area_name IS NOT NULL, '/', ''), IFNULL(l3.area_name, '') ) AS areaNameDisplay, h.address, h.longitude, h.latitude, h.hazard_desc AS hazardDesc, h.rectify_start_date AS rectifyStartDate, h.rectify_end_date AS rectifyEndDate, h.submit_user_name AS submitUserName, h.submit_time AS submitTime, h.assignee_id AS assigneeId, w.name AS assigneeName, h.is_self_rectify AS isSelfRectify, h.hazard_photo AS hazardPhoto, h.rectify_status AS rectifyStatus, h.rectify_photo AS rectifyPhoto, h.rectify_video AS rectifyVideo, h.rectify_time AS rectifyTime FROM gas_hazard_info h LEFT JOIN gas_user u ON h.user_id = u.id LEFT JOIN gas_worker w ON h.assignee_id = w.id LEFT JOIN tbl_area_node l3 ON CASE WHEN h.area_code LIKE '%/%/%' THEN SUBSTRING_INDEX(h.area_code, '/', -1) ELSE NULL END = l3.code LEFT JOIN tbl_area_node l2 ON CASE WHEN h.area_code LIKE '%/%/%' THEN SUBSTRING_INDEX(SUBSTRING_INDEX(h.area_code, '/', 2), '/', -1) WHEN h.area_code LIKE '%/%' THEN SUBSTRING_INDEX(h.area_code, '/', -1) ELSE NULL END = l2.code LEFT JOIN tbl_area_node l1 ON CASE WHEN h.area_code LIKE '%/%' THEN SUBSTRING_INDEX(h.area_code, '/', 1) ELSE NULL END = l1.code WHERE 1=1
AND h.hazard_type = #{hazardType}
AND h.hazard_level = #{hazardLevel}
AND h.hazard_source = #{hazardSource}
AND h.address LIKE CONCAT('%', #{address}, '%')
AND h.submit_user_name LIKE CONCAT('%', #{submitUserName}, '%')
ORDER BY h.submit_time DESC LIMIT #{start}, #{length}

SELECT COUNT(*)
FROM gas_hazard_info h
WHERE 1=1

    AND h.hazard_type = #{hazardType}


    AND h.hazard_level = #{hazardLevel}


    AND h.hazard_source = #{hazardSource}


    AND h.address LIKE CONCAT('%', #{address}, '%')


    AND h.submit_user_name LIKE CONCAT('%', #{submitUserName}, '%')

